{"code": "import json
import re
from collections import defaultdict, Counter

# Load the full business data
businesses_path = var_functions.query_db:12
if isinstance(businesses_path, str) and businesses_path.endswith('.json'):
    with open(businesses_path, 'r') as f:
        businesses = json.load(f)
else:
    businesses = businesses_path

# Load the full review data
reviews_path = var_functions.query_db:16
if isinstance(reviews_path, str) and reviews_path.endswith('.json'):
    with open(reviews_path, 'r') as f:
        reviews = json.load(f)
else:
    reviews = reviews_path

# Extract business ID and categories
business_categories = {}
for b in businesses:
    business_id = b['business_id']  # e.g., businessid_49
    # Remove prefix and convert to businessref_ format
    business_num = business_id.replace('businessid_', '')
    business_ref = f'businessref_{business_num}'

    # Extract categories from description
    desc = b.get('description', '')
    # Find the part after "services in" or similar patterns
    if 'services in' in desc:
        categories_part = desc.split('services in')[1].strip()
    elif 'services including' in desc:
        categories_part = desc.split('services including')[1].strip()
    elif 'category of' in desc:
        categories_part = desc.split('category of')[1].strip()
    elif 'offers a range of services' in desc:
        categories_part = desc.split('offers a range of services')[1].strip()
        if 'including' in categories_part:
            categories_part = categories_part.split('including')[1].strip()
        elif 'in the fields of' in categories_part:
            categories_part = categories_part.split('in the fields of')[1].strip()
        elif 'in the categories of' in categories_part:
            categories_part = categories_part.split('in the categories of')[1].strip()
    else:
        categories_part = desc

    # Remove trailing period
    categories_part = categories_part.rstrip('.')

    # Split by comma or 'and'
    categories = re.split(r',\s*|\sand\s', categories_part)
    categories = [cat.strip() for cat in categories if cat.strip()]

    business_categories[business_ref] = {
        'categories': categories,
        'name': b.get('name', '')
    }

# Group businesses by category
category_businesses = defaultdict(list)
for business_ref, data in business_categories.items():
    for cat in data['categories']:
        category_businesses[cat].append(business_ref)

# Count businesses per category
category_counts = {cat: len(businesses) for cat, businesses in category_businesses.items()}

# Sort by count descending
sorted_categories = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'top_10_categories': sorted_categories[:10],
    'total_businesses_with_cc': len(businesses),
    'total_categories': len(category_counts)
}))"}
